REQUEST.BODY_JSON_SCHEMA:

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "user_id": {
      "type": "string",
      "format": "uuid",
      "description": "Unique UUID identifying the student session"
    },
    "mood": {
      "type": "string",
      "enum": ["great", "good", "okay", "anxious", "overwhelmed"],
      "description": "Selected mood option"
    },
    "journal_text": {
      "type": "string",
      "maxLength": 5000,
      "description": "Open-ended journal input text written by the student"
    }
  },
  "required": ["user_id", "mood", "journal_text"]
}

REQUEST.EXAMPLE_PAYLOAD:

{
  "user_id": "f51bbd8d-3b28-4e09-b68a-ef83d1c1bb84",
  "mood": "overwhelmed",
  "journal_text": "I spent 5 hours on physics numerical mock questions today and got most of them wrong. I feel like I am failing JEE preparation. Peer group pressure from coaching class is stressing me out."
}

RESPONSE.BODY_JSON_SCHEMA:

{
  "type": "object",
  "properties": {
    "success": { "type": "boolean" },
    "data": {
      "type": "object",
      "properties": {
        "id": { "type": "string", "format": "uuid" },
        "user_id": { "type": "string", "format": "uuid" },
        "mood": { "type": "string" },
        "journal_text": { "type": "string" },
        "dominant_emotion": { "type": "string", "description": "Extracted dominant emotion" },
        "triggers": {
          "type": "array",
          "items": { "type": "string" },
          "description": "List of extracted exam-prep triggers"
        },
        "created_at": { "type": "string", "format": "date-time" }
      },
      "required": ["id", "user_id", "mood", "journal_text", "dominant_emotion", "triggers", "created_at"]
    }
  },
  "required": ["success", "data"]
}

RESPONSE.EXAMPLE_RESPONSE:

{
  "success": true,
  "data": {
    "id": "a1d35ef6-d922-4467-8c3b-d2426617ba8d",
    "user_id": "f51bbd8d-3b28-4e09-b68a-ef83d1c1bb84",
    "mood": "overwhelmed",
    "journal_text": "I spent 5 hours on physics numerical mock questions today and got most of them wrong. I feel like I am failing JEE preparation. Peer group pressure from coaching class is stressing me out.",
    "dominant_emotion": "defeat/anxiety",
    "triggers": ["physics numericals", "mock test failure", "peer pressure", "coaching class"],
    "created_at": "2026-06-13T12:00:00.000Z"
  }
}

ERROR.EXAMPLE_BODY:

{
  "success": false,
  "error": "Validation failed: 'mood' is required and must be one of the allowed values."
}


{
  "success": false,
  "error": "Failed to process log: Groq API did not respond."
}

RESPONSE.BODY_JSON_SCHEMA:

{
  "type": "object",
  "properties": {
    "success": { "type": "boolean" },
    "data": {
      "type": "object",
      "properties": {
        "logs": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "id": { "type": "string", "format": "uuid" },
              "mood": { "type": "string" },
              "dominant_emotion": { "type": "string" },
              "triggers": { "type": "array", "items": { "type": "string" } },
              "created_at": { "type": "string", "format": "date-time" }
            },
            "required": ["id", "mood", "dominant_emotion", "triggers", "created_at"]
          }
        },
        "mood_trend": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "date": { "type": "string", "description": "YYYY-MM-DD format" },
              "mood_score": { "type": "number", "description": "Numeric score mapping of mood" }
            },
            "required": ["date", "mood_score"]
          }
        },
        "trigger_frequencies": {
          "type": "object",
          "additionalProperties": { "type": "integer" },
          "description": "Key-value pair of trigger term and its count"
        }
      },
      "required": ["logs", "mood_trend", "trigger_frequencies"]
    }
  },
  "required": ["success", "data"]
}

