REQUEST.BODY_JSON_SCHEMA:

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "user_id": { "type": "string", "format": "uuid" },
    "message": { "type": "string", "maxLength": 2000, "description": "Student's message content" },
    "history": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "role": { "type": "string", "enum": ["user", "assistant"] },
          "content": { "type": "string" }
        },
        "required": ["role", "content"]
      },
      "description": "Conversation context history (last 5-10 messages max)"
    }
  },
  "required": ["user_id", "message", "history"]
}

REQUEST.EXAMPLE_PAYLOAD:

{
  "user_id": "f51bbd8d-3b28-4e09-b68a-ef83d1c1bb84",
  "message": "I'm feeling so anxious about the upcoming NEET mockup exam. I can't sleep or study.",
  "history": []
}

RESPONSE.BODY_JSON_SCHEMA:

{
  "type": "object",
  "properties": {
    "success": { "type": "boolean" },
    "flagged": { "type": "boolean", "description": "Indicates if crisis bypass was triggered" },
    "response": { "type": "string", "description": "The AI's message response or crisis safety message" },
    "grounding_source": { "type": "string", "description": "Reference source from WHO or MoHFW, if applicable" },
    "resources": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "name": { "type": "string" },
          "phone": { "type": "string" },
          "availability": { "type": "string" }
        },
        "required": ["name", "phone"]
      },
      "description": "Helplines provided if flagged=true"
    }
  },
  "required": ["success", "flagged", "response"]
}

RESPONSE.EXAMPLE_RESPONSE_CLEAN:

{
  "success": true,
  "flagged": false,
  "response": "It's completely natural to feel anxious when preparing for a high-stakes exam like NEET. When anxiety builds up, trying a quick breathing exercise can help ground you. You might try 'Box Breathing': inhale for 4 seconds, hold for 4, exhale for 4, and hold for 4. Studies cited in WHO stress-management guidelines show that slow breathing patterns signal to your brain that it is safe, helping to lower heart rate and restore focus.",
  "grounding_source": "WHO Guidelines on Stress Management (2020)"
}

RESPONSE.EXAMPLE_RESPONSE_FLAGGED:

{
  "success": true,
  "flagged": true,
  "response": "It sounds like you are going through an incredibly difficult time right now, and I want to make sure you have immediate support. Please connect with a professional counselor or helpline who can help you navigate this safely. You do not have to go through this alone.",
  "resources": [
    {
      "name": "Kiran Mental Health Helpline (Ministry of Social Justice & Empowerment)",
      "phone": "1800-599-0019",
      "availability": "24/7"
    },
    {
      "name": "AASRA Suicide Prevention Helpline",
      "phone": "+91-9820466726",
      "availability": "24/7"
    }
  ]
}
